import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.util.Scanner;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        // Escape user input to prevent XSS
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String safeUserName = codec.encodeForHTML(userName);

        // Output the sanitized user input
        System.out.println("<p>Welcome, " + safeUserName + "!</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
